-- =====================================================================
-- CUSTOMER: self-service ownership
-- =====================================================================
create policy customer_self_select on customers
  for select to authenticated using (profile_id = auth.uid());
create policy customer_self_update on customers
  for update to authenticated
  using (profile_id = auth.uid()) with check (profile_id = auth.uid());

create policy profile_self_select on profiles
  for select to authenticated using (id = auth.uid());
create policy profile_self_update on profiles
  for update to authenticated
  using (id = auth.uid()) with check (id = auth.uid());

create policy address_owner_all on customer_addresses
  for all to authenticated
  using (public.owns_customer(customer_id))
  with check (public.owns_customer(customer_id));

create policy wishlist_owner_all on wishlist
  for all to authenticated
  using (public.owns_customer(customer_id))
  with check (public.owns_customer(customer_id));

create policy cart_owner_all on cart
  for all to authenticated
  using (public.owns_customer(customer_id))
  with check (public.owns_customer(customer_id));

create policy cart_items_owner_all on cart_items
  for all to authenticated
  using (exists (
    select 1 from cart c
    where c.id = cart_items.cart_id and public.owns_customer(c.customer_id)))
  with check (exists (
    select 1 from cart c
    where c.id = cart_items.cart_id and public.owns_customer(c.customer_id)));

create policy orders_owner_select on orders
  for select to authenticated using (public.owns_customer(customer_id));

create policy order_items_owner_select on order_items
  for select to authenticated
  using (exists (
    select 1 from orders o
    where o.id = order_items.order_id and public.owns_customer(o.customer_id)));

create policy reviews_owner_write on reviews
  for all to authenticated
  using (public.owns_customer(customer_id))
  with check (public.owns_customer(customer_id));

create policy notifications_owner on notifications
  for all to authenticated
  using (user_id = auth.uid()) with check (user_id = auth.uid());

create policy tickets_owner_select on support_tickets
  for select to authenticated using (public.owns_customer(customer_id));
create policy tickets_owner_insert on support_tickets
  for insert to authenticated with check (public.owns_customer(customer_id));

create policy ticket_messages_owner on ticket_messages
  for select to authenticated
  using (exists (
    select 1 from support_tickets t
    where t.id = ticket_messages.ticket_id
      and public.owns_customer(t.customer_id)));

-- =====================================================================
-- FILE: 004_storage.sql
-- =====================================================================

-- =====================================================================
-- BeyondBabyCo — 004_storage.sql
-- Storage buckets and access policies.
-- =====================================================================

-- ---------------------------------------------------------------------
-- Buckets
--   products, homepage, mascots, blog  -> public read
--   media, documents                   -> private (staff only)
-- ---------------------------------------------------------------------
insert into storage.buckets (id, name, public) values
  ('products',  'products',  true),
  ('homepage',  'homepage',  true),
  ('mascots',   'mascots',   true),
  ('blog',      'blog',      true),
  ('media',     'media',     false),
  ('documents', 'documents', false)
on conflict (id) do nothing;

-- ---------------------------------------------------------------------
-- Public buckets: anyone can read; only managers/admins can write.
-- ---------------------------------------------------------------------
do $$
declare
  b text;
  public_buckets text[] := array['products','homepage','mascots','blog'];
begin
  foreach b in array public_buckets loop
    execute format($f$
      drop policy if exists "public_read_%1$s" on storage.objects;
      create policy "public_read_%1$s" on storage.objects
        for select to anon, authenticated
        using (bucket_id = %1$L);
    $f$, b);

    execute format($f$
      drop policy if exists "manager_write_%1$s" on storage.objects;
      create policy "manager_write_%1$s" on storage.objects
        for all to authenticated
        using (bucket_id = %1$L and public.is_manager())
        with check (bucket_id = %1$L and public.is_manager());
    $f$, b);
  end loop;
end $$;

-- ---------------------------------------------------------------------
-- Private buckets: staff read, manager write.
-- ---------------------------------------------------------------------
do $$
declare
  b text;
  private_buckets text[] := array['media','documents'];
begin
  foreach b in array private_buckets loop
    execute format($f$
      drop policy if exists "staff_read_%1$s" on storage.objects;
      create policy "staff_read_%1$s" on storage.objects
        for select to authenticated
        using (bucket_id = %1$L and public.is_staff());
    $f$, b);

    execute format($f$
      drop policy if exists "manager_write_%1$s" on storage.objects;
      create policy "manager_write_%1$s" on storage.objects
        for all to authenticated
        using (bucket_id = %1$L and public.is_manager())
        with check (bucket_id = %1$L and public.is_manager());
    $f$, b);
  end loop;
end $$;

