-- =====================================================================
-- FILE: 006_auth_functions.sql
-- =====================================================================

-- =====================================================================
-- BeyondBabyCo — 006_auth_functions.sql
-- Auth/authorization RPCs used by the Next.js app (Phase 4.3).
-- All SECURITY DEFINER so authenticated users can resolve their own
-- role/permissions and write audit entries without broad table grants.
-- =====================================================================

-- Resolve the signed-in user's role name (or null).
create or replace function public.current_user_role()
returns text
language sql
stable
security definer
set search_path = public
as $$
  select r.name
  from profiles p
  join roles r on r.id = p.role_id
  where p.id = auth.uid()
    and p.is_active
  limit 1;
$$;

-- Resolve the flattened permission codes for the signed-in user.
create or replace function public.current_user_permissions()
returns setof text
language sql
stable
security definer
set search_path = public
as $$
  select distinct perm.code
  from profiles p
  join role_permissions rp on rp.role_id = p.role_id
  join permissions perm on perm.id = rp.permission_id
  where p.id = auth.uid()
    and p.is_active;
$$;

-- Write an audit entry to activity_logs as the signed-in user.
create or replace function public.log_activity(
  p_action    text,
  p_entity    text default null,
  p_entity_id uuid default null,
  p_metadata  jsonb default '{}'::jsonb
)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into activity_logs (actor_id, action, entity, entity_id, metadata)
  values (auth.uid(), p_action, p_entity, p_entity_id, coalesce(p_metadata, '{}'::jsonb));
end;
$$;

grant execute on function public.current_user_role()         to authenticated;
grant execute on function public.current_user_permissions()  to authenticated;
grant execute on function public.log_activity(text, text, uuid, jsonb) to authenticated;

-- =====================================================================
-- FILE: 007_products_admin.sql
-- =====================================================================

-- =====================================================================
-- BeyondBabyCo — 007_products_admin.sql
-- Columns + RPC needed by the Product Management module (Phase 4.5).
-- Additive and idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- Extend products with merchandising, pricing, logistics, SEO and
-- soft-delete fields used by the admin product form.
-- (Stock is denormalized here for the admin module; the normalized
--  inventory tables remain the source of truth once Inventory ships.)
-- ---------------------------------------------------------------------
alter table products
  add column if not exists sale_price          numeric(12,2) check (sale_price >= 0),
  add column if not exists gst_rate            numeric(5,2)  not null default 0 check (gst_rate >= 0),
  add column if not exists tax_class           text,
  add column if not exists barcode             text,
  add column if not exists stock               integer not null default 0 check (stock >= 0),
  add column if not exists low_stock_threshold integer not null default 0 check (low_stock_threshold >= 0),
  add column if not exists weight_grams        integer check (weight_grams >= 0),
  add column if not exists length_cm           numeric(8,2) check (length_cm >= 0),
  add column if not exists width_cm            numeric(8,2) check (width_cm >= 0),
  add column if not exists height_cm           numeric(8,2) check (height_cm >= 0),
  add column if not exists is_best_seller      boolean not null default false,
  add column if not exists is_new_arrival      boolean not null default false,
  add column if not exists is_trending         boolean not null default false,
  add column if not exists launch_date         timestamptz,
  add column if not exists seo_title           text,
  add column if not exists seo_description     text,
  add column if not exists meta_keywords       text,
  add column if not exists canonical_url       text,
  add column if not exists deleted_at          timestamptz;

-- Active (non-deleted) products are the common query path.
create index if not exists idx_products_not_deleted
  on products(deleted_at) where deleted_at is null;

-- ---------------------------------------------------------------------
-- Audit helper — writes to audit_logs as the signed-in user.
-- SECURITY DEFINER so managers (who lack direct insert on audit_logs)
-- can still record changes.
-- ---------------------------------------------------------------------
create or replace function public.log_audit(
  p_table  text,
  p_record uuid,
  p_action text,
  p_old    jsonb default null,
  p_new    jsonb default null
)
returns void
language plpgsql
security definer
set search_path = public
as $$
begin
  insert into audit_logs (table_name, record_id, action, old_data, new_data, changed_by)
  values (p_table, p_record, p_action, p_old, p_new, auth.uid());
end;
$$;

grant execute on function public.log_audit(text, uuid, text, jsonb, jsonb) to authenticated;

-- =====================================================================
-- FILE: 008_categories_brands_admin.sql
-- =====================================================================

-- =====================================================================
-- 008_categories_brands_admin.sql
-- Phase 4.6 — Enterprise Categories & Brands
--
-- Additive migration that extends the existing `categories` and `brands`
-- tables (created in 001_initial_schema.sql) with the merchandising, media,
-- SEO, publishing and soft-delete fields the admin modules need.
--
-- Safe to run multiple times (idempotent: add column if not exists, etc.).
-- =====================================================================

-- ---------------------------------------------------------------------
-- Categories
-- ---------------------------------------------------------------------
alter table categories
  add column if not exists banner_url       text,
  add column if not exists icon_url         text,
  add column if not exists seo_title        text,
  add column if not exists seo_description  text,
  add column if not exists meta_keywords    text,
  add column if not exists canonical_url    text,
  add column if not exists is_featured      boolean not null default false,
  add column if not exists status           text not null default 'draft'
    check (status in ('draft', 'active', 'archived')),
  add column if not exists deleted_at       timestamptz;

-- ---------------------------------------------------------------------
-- Brands
-- ---------------------------------------------------------------------
alter table brands
  add column if not exists website_url       text,
  add column if not exists country_of_origin text,
  add column if not exists banner_url        text,
  add column if not exists seo_title         text,
  add column if not exists seo_description   text,
  add column if not exists meta_keywords     text,
  add column if not exists canonical_url     text,
  add column if not exists is_featured       boolean not null default false,
  add column if not exists position          integer not null default 0,
  add column if not exists status            text not null default 'draft'
    check (status in ('draft', 'active', 'archived')),
  add column if not exists deleted_at        timestamptz;

-- ---------------------------------------------------------------------
-- Backfill: keep the new `status` column aligned with the legacy
-- `is_active` flag for rows that pre-date this migration.
-- ---------------------------------------------------------------------
update categories set status = 'active' where is_active = true  and status = 'draft';
update brands     set status = 'active' where is_active = true  and status = 'draft';

-- ---------------------------------------------------------------------
-- Indexes
-- ---------------------------------------------------------------------
create index if not exists idx_categories_not_deleted on categories(deleted_at) where deleted_at is null;
create index if not exists idx_categories_parent_pos  on categories(parent_id, position);
create index if not exists idx_categories_status      on categories(status);
create index if not exists idx_brands_not_deleted     on brands(deleted_at) where deleted_at is null;
create index if not exists idx_brands_status          on brands(status);
create index if not exists idx_brands_position        on brands(position);

-- ---------------------------------------------------------------------
-- Storage: category & brand assets live in the (private) `media` bucket
-- under the `categories/` and `brands/` prefixes. These prefixes hold
-- public-facing imagery (logos, banners), so allow public read on them
-- while the rest of the media bucket stays staff-only.
-- ---------------------------------------------------------------------
drop policy if exists "public_read_media_catalog" on storage.objects;
create policy "public_read_media_catalog" on storage.objects
  for select
  to anon, authenticated
  using (
    bucket_id = 'media'
    and (name like 'categories/%' or name like 'brands/%')
  );

-- =====================================================================
-- FILE: 009_media_library.sql
-- =====================================================================

-- =====================================================================
-- 009_media_library.sql
-- Phase 4.7 — Enterprise Media Library
--
-- Extends the existing `media_folders` and `media_library` tables
-- (created in 001_initial_schema.sql) into a full digital-asset manager
-- mapped to Supabase Storage. Adds the `media.manage` permission and seeds
-- the system folders that mirror the storage buckets.
--
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- media_folders — bucket-aware folder tree (system + custom).
-- ---------------------------------------------------------------------
alter table media_folders
  add column if not exists slug        text,
  add column if not exists bucket      text,
  add column if not exists path_prefix text not null default '',
  add column if not exists icon        text,
  add column if not exists is_system   boolean not null default false,
  add column if not exists position    integer not null default 0;

create unique index if not exists uq_media_folders_slug on media_folders(slug) where slug is not null;

-- ---------------------------------------------------------------------
-- media_library — add image-optimization metadata.
-- ---------------------------------------------------------------------
alter table media_library
  add column if not exists original_name text,
  add column if not exists width         integer check (width  >= 0),
  add column if not exists height        integer check (height >= 0),
  add column if not exists blur_data_url text;

create index if not exists idx_media_library_bucket  on media_library(bucket);
create index if not exists idx_media_library_folder  on media_library(folder_id);
create index if not exists idx_media_library_created on media_library(created_at desc);
create index if not exists idx_media_library_mime    on media_library(mime_type);
create index if not exists idx_media_library_name_trgm on media_library using gin (original_name gin_trgm_ops);

-- ---------------------------------------------------------------------
-- Permission: media.manage  (+ map to admin & manager)
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('media.manage', 'Manage the media library and storage assets.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'media.manage'
where r.name in ('admin', 'manager')
on conflict do nothing;

-- Seed system folders (mirror the storage buckets / known prefixes).
-- Uses WHERE NOT EXISTS — partial unique index on slug is not valid for ON CONFLICT (slug).
insert into media_folders (name, slug, bucket, path_prefix, icon, is_system, position)
select v.name, v.slug, v.bucket, v.path_prefix, v.icon, v.is_system, v.position
from (
  values
    ('Products',   'products',   'products',  '',            'products',   true, 1),
    ('Homepage',   'homepage',   'homepage',  '',            'homepage',   true, 2),
    ('Categories', 'categories', 'media',     'categories/', 'categories', true, 3),
    ('Brands',     'brands',     'media',     'brands/',     'brands',     true, 4),
    ('Mascots',    'mascots',    'mascots',   '',            'sparkles',   true, 5),
    ('Blog',       'blog',       'blog',      '',            'blog',       true, 6),
    ('Documents',  'documents',  'documents', '',            'blog',       true, 7)
) as v(name, slug, bucket, path_prefix, icon, is_system, position)
where not exists (
  select 1 from media_folders mf where mf.slug is not distinct from v.slug
);

-- =====================================================================
-- FILE: 010_homepage_cms.sql
-- =====================================================================

-- =====================================================================
-- 010_homepage_cms.sql
-- Phase 4.8 — Enterprise Homepage CMS
--
-- Adds the `cms.manage` permission, extends `hero_slides` with the extra
-- fields the hero editor needs, and seeds the default homepage sections +
-- global settings rows. Uses the existing CMS tables created in
-- 001_initial_schema.sql (homepage_settings, homepage_sections, hero_slides,
-- testimonials, banners) — all already covered by RLS in 003_rls.sql.
--
-- Additive + idempotent.
-- =====================================================================

