  ('featured_categories', 'Featured Categories', 3,  true,  '{"limit":6,"categoryIds":[]}'::jsonb),
  ('featured_products',   'Featured Products',   4,  true,  '{"limit":8,"productIds":[]}'::jsonb),
  ('brand_promise',       'Brand Promise',       5,  true,  '{"cards":[]}'::jsonb),
  ('science',             'Science Section',     6,  true,  '{"features":[]}'::jsonb),
  ('lifestyle',           'Lifestyle',           7,  true,  '{"cards":[]}'::jsonb),
  ('mascots',             'Mascots',             8,  true,  '{"items":[]}'::jsonb),
  ('research_timeline',   'Research Timeline',   9,  true,  '{"entries":[]}'::jsonb),
  ('testimonials',        'Testimonials',        10, true,  '{}'::jsonb),
  ('newsletter',          'Newsletter',          11, true,  '{}'::jsonb)
on conflict (key) do nothing;

-- ---------------------------------------------------------------------
-- Seed global settings rows (no toggle).
-- ---------------------------------------------------------------------
insert into homepage_settings (key, value) values
  ('general',  '{}'::jsonb),
  ('seo',      '{}'::jsonb),
  ('footer',   '{}'::jsonb),
  ('publish',  '{"status":"draft"}'::jsonb)
on conflict (key) do nothing;

-- =====================================================================
-- FILE: 011_inventory_warehouse.sql
-- =====================================================================

-- =====================================================================
-- 011_inventory_warehouse.sql
-- Phase 4.9 — Enterprise Inventory & Warehouse
--
-- Extends warehouses, suppliers, purchase orders and stock movements for
-- the inventory admin module. Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- movement_type — richer movement categories for the admin UI
-- ---------------------------------------------------------------------
alter type movement_type add value if not exists 'purchase';
alter type movement_type add value if not exists 'sale';
alter type movement_type add value if not exists 'return';

-- ---------------------------------------------------------------------
-- warehouses
-- ---------------------------------------------------------------------
alter table warehouses
  add column if not exists contact_person text,
  add column if not exists phone          text,
  add column if not exists email          text,
  add column if not exists is_default     boolean not null default false;

create unique index if not exists idx_warehouses_single_default
  on warehouses (is_default) where is_default = true;

-- ---------------------------------------------------------------------
-- suppliers
-- ---------------------------------------------------------------------
alter table suppliers
  add column if not exists contact_name text,
  add column if not exists country      text default 'India',
  add column if not exists website      text,
  add column if not exists notes        text;

-- ---------------------------------------------------------------------
-- purchase_orders — sent/received lifecycle
-- ---------------------------------------------------------------------
alter table purchase_orders
  add column if not exists received_at timestamptz,
  add column if not exists notes       text;

alter table purchase_orders drop constraint if exists purchase_orders_status_check;
update purchase_orders set status = 'sent' where status = 'ordered';
alter table purchase_orders add constraint purchase_orders_status_check
  check (status in ('draft','sent','received','cancelled'));

-- ---------------------------------------------------------------------
-- purchase_order_items — partial receiving
-- ---------------------------------------------------------------------
alter table purchase_order_items
  add column if not exists quantity_received integer not null default 0
    check (quantity_received >= 0);

-- ---------------------------------------------------------------------
-- stock_movements — adjustment reason
-- ---------------------------------------------------------------------
alter table stock_movements
  add column if not exists reason text;

create index if not exists idx_stock_moves_created on stock_movements(created_at desc);
create index if not exists idx_po_status           on purchase_orders(status);
create index if not exists idx_po_expected         on purchase_orders(expected_at);

-- =====================================================================
-- FILE: 012_orders_fulfillment.sql
-- =====================================================================

-- =====================================================================
-- 012_orders_fulfillment.sql
-- Phase 4.10 — Enterprise Orders & Fulfillment
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- order_status — add lifecycle states used by the admin UI
-- ---------------------------------------------------------------------
alter type order_status add value if not exists 'draft';
alter type order_status add value if not exists 'packed';
alter type order_status add value if not exists 'completed';

-- ---------------------------------------------------------------------
-- orders — warehouse, notes, cancellation metadata
-- ---------------------------------------------------------------------
alter table orders
  add column if not exists warehouse_id   uuid references warehouses(id) on delete set null,
  add column if not exists notes          text,
  add column if not exists internal_notes text,
  add column if not exists cancelled_at   timestamptz,
  add column if not exists cancel_reason  text;

create index if not exists idx_orders_status      on orders(status);
create index if not exists idx_orders_customer    on orders(customer_id);
create index if not exists idx_orders_warehouse   on orders(warehouse_id);
create index if not exists idx_orders_created     on orders(created_at desc);
create index if not exists idx_orders_placed      on orders(placed_at desc);

-- ---------------------------------------------------------------------
-- shipments — warehouse, package details, ETA
-- ---------------------------------------------------------------------
alter table shipments
  add column if not exists warehouse_id         uuid references warehouses(id) on delete set null,
  add column if not exists weight_grams         integer check (weight_grams >= 0),
  add column if not exists dimensions           jsonb not null default '{}'::jsonb,
  add column if not exists estimated_delivery   timestamptz;

create index if not exists idx_shipments_order    on shipments(order_id);
create index if not exists idx_shipments_status   on shipments(status);
create index if not exists idx_shipments_tracking on shipments(tracking_number);

-- ---------------------------------------------------------------------
-- order_events — unified timeline for status, notes, refunds, docs
-- ---------------------------------------------------------------------
create table if not exists order_events (
  id         uuid primary key default gen_random_uuid(),
  order_id   uuid not null references orders(id) on delete cascade,
  type       text not null,
  message    text not null,
  metadata   jsonb not null default '{}'::jsonb,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now()
);

create index if not exists idx_order_events_order on order_events(order_id, created_at desc);

-- ---------------------------------------------------------------------
-- order_refunds
-- ---------------------------------------------------------------------
create table if not exists order_refunds (
  id         uuid primary key default gen_random_uuid(),
  order_id   uuid not null references orders(id) on delete cascade,
  payment_id uuid references payments(id) on delete set null,
  amount     numeric(14,2) not null check (amount >= 0),
  reason     text,
  notes      text,
  status     payment_status not null default 'refunded',
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now()
);

create index if not exists idx_order_refunds_order on order_refunds(order_id);

-- RLS: managers already have access via manager_all policy on orders table group.
-- Seed order_events + order_refunds into manager tables if not already covered.
do $$
begin
  execute 'drop policy if exists manager_all on public.order_events';
  execute 'create policy manager_all on public.order_events for all to authenticated using (public.is_manager()) with check (public.is_manager())';
  execute 'drop policy if exists manager_all on public.order_refunds';
  execute 'create policy manager_all on public.order_refunds for all to authenticated using (public.is_manager()) with check (public.is_manager())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 013_customers_crm.sql
-- =====================================================================

-- =====================================================================
-- 013_customers_crm.sql
-- Phase 4.11 — Enterprise Customers & CRM
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- customers — CRM profile fields
-- ---------------------------------------------------------------------
alter table customers
  add column if not exists status         text not null default 'active'
    check (status in ('active','inactive','deleted')),
  add column if not exists avatar_url     text,
  add column if not exists notes          text,
  add column if not exists internal_notes text,
  add column if not exists tags           jsonb not null default '[]'::jsonb,
  add column if not exists is_vip         boolean not null default false,
  add column if not exists deleted_at     timestamptz;

create index if not exists idx_customers_status    on customers(status);
create index if not exists idx_customers_vip       on customers(is_vip) where is_vip = true;
create index if not exists idx_customers_created   on customers(created_at desc);
create index if not exists idx_customers_deleted   on customers(deleted_at) where deleted_at is not null;

-- ---------------------------------------------------------------------
-- customer_events — activity timeline
-- ---------------------------------------------------------------------
create table if not exists customer_events (
  id          uuid primary key default gen_random_uuid(),
  customer_id uuid not null references customers(id) on delete cascade,
  type        text not null,
  message     text not null,
  metadata    jsonb not null default '{}'::jsonb,
  created_by  uuid references profiles(id) on delete set null,
  created_at  timestamptz not null default now()
);

create index if not exists idx_customer_events_customer on customer_events(customer_id, created_at desc);

-- ---------------------------------------------------------------------
-- Permission: customers.manage
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('customers.manage', 'Create, edit, merge and manage customer records.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'customers.manage'
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS for customer_events
do $$
begin
  execute 'drop policy if exists manager_all on public.customer_events';
  execute 'create policy manager_all on public.customer_events for all to authenticated using (public.is_manager()) with check (public.is_manager())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 014_reviews_moderation.sql
-- =====================================================================

-- =====================================================================
-- 014_reviews_moderation.sql
-- Phase 4.12 — Enterprise Reviews & Moderation
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- reviews — moderation fields
-- ---------------------------------------------------------------------
alter table reviews
  add column if not exists moderation_status text not null default 'pending'
    check (moderation_status in ('pending','approved','rejected','hidden','spam')),
  add column if not exists pros              text,
  add column if not exists cons              text,
  add column if not exists is_featured       boolean not null default false,
  add column if not exists internal_notes    text,
  add column if not exists moderator_id      uuid references profiles(id) on delete set null,
  add column if not exists moderation_reason text,
  add column if not exists edited_at         timestamptz,
  add column if not exists deleted_at        timestamptz;

-- Backfill from legacy is_published
update reviews
set moderation_status = case when is_published then 'approved' else 'pending' end
where moderation_status = 'pending' and is_published = true;

create index if not exists idx_reviews_moderation   on reviews(moderation_status);
create index if not exists idx_reviews_featured     on reviews(is_featured) where is_featured = true;
create index if not exists idx_reviews_rating       on reviews(rating);
create index if not exists idx_reviews_created      on reviews(created_at desc);
create index if not exists idx_reviews_deleted      on reviews(deleted_at) where deleted_at is not null;

-- ---------------------------------------------------------------------
-- review_events — moderation history timeline
-- ---------------------------------------------------------------------
create table if not exists review_events (
  id         uuid primary key default gen_random_uuid(),
  review_id  uuid not null references reviews(id) on delete cascade,
  type       text not null,
  message    text not null,
  metadata   jsonb not null default '{}'::jsonb,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now()
);

create index if not exists idx_review_events_review on review_events(review_id, created_at desc);

-- ---------------------------------------------------------------------
-- Permission: reviews.manage
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('reviews.manage', 'Moderate product reviews and featured ratings.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'reviews.manage'
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS for review_events
do $$
begin
  execute 'drop policy if exists manager_all on public.review_events';
  execute 'create policy manager_all on public.review_events for all to authenticated using (public.is_manager()) with check (public.is_manager())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 015_returns_rma.sql
-- =====================================================================

-- =====================================================================
-- 015_returns_rma.sql
-- Phase 4.13 — Enterprise Returns & RMA
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- returns
-- ---------------------------------------------------------------------
create table if not exists returns (
  id              uuid primary key default gen_random_uuid(),
  rma_number      text not null unique,
  order_id        uuid not null references orders(id) on delete restrict,
  customer_id     uuid references customers(id) on delete set null,
  warehouse_id    uuid references warehouses(id) on delete set null,
  status          text not null default 'requested'
                  check (status in (
                    'requested','approved','rejected','pickup_scheduled',
                    'received','inspection','refund_approved','refunded','closed'
                  )),
  reason          text not null default 'other'
                  check (reason in (
                    'damaged','wrong_item','missing_item','quality_issue',
                    'expired','customer_changed_mind','other'
                  )),
  refund_status   text not null default 'pending'
                  check (refund_status in (
                    'pending','partial','full','store_credit','gift_card','refunded','none'
                  )),
  refund_type     text
                  check (refund_type is null or refund_type in (
                    'partial','full','store_credit','gift_card'
                  )),
  refund_amount   numeric(14,2) not null default 0 check (refund_amount >= 0),
  inspection_notes text,
  inspector_id    uuid references profiles(id) on delete set null,
  internal_notes  text,
  restock_completed boolean not null default false,
  closed_at       timestamptz,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists idx_returns_status     on returns(status);
create index if not exists idx_returns_order      on returns(order_id);
create index if not exists idx_returns_customer   on returns(customer_id);
create index if not exists idx_returns_warehouse  on returns(warehouse_id);
create index if not exists idx_returns_refund     on returns(refund_status);
create index if not exists idx_returns_created    on returns(created_at desc);

-- ---------------------------------------------------------------------
-- return_items
-- ---------------------------------------------------------------------
create table if not exists return_items (
  id                  uuid primary key default gen_random_uuid(),
  return_id           uuid not null references returns(id) on delete cascade,
  order_item_id       uuid references order_items(id) on delete set null,
  product_id          uuid references products(id) on delete set null,
  product_variant_id  uuid references product_variants(id) on delete set null,
  name                text not null,
  sku                 text,
  quantity            integer not null check (quantity > 0),
  unit_price          numeric(12,2) not null default 0 check (unit_price >= 0),
  condition           text,
  restock_decision    text
                      check (restock_decision is null or restock_decision in (
                        'good','damaged','destroy','vendor_return'
                      )),
  damage_level        text
                      check (damage_level is null or damage_level in (
                        'none','minor','major','total'
                      )),
  inspection_photos   jsonb not null default '[]'::jsonb,
  inspector_notes     text,
  restocked           boolean not null default false,
  created_at          timestamptz not null default now(),
  updated_at          timestamptz not null default now()
);

create index if not exists idx_return_items_return on return_items(return_id);

-- ---------------------------------------------------------------------
-- return_events — timeline
-- ---------------------------------------------------------------------
create table if not exists return_events (
  id         uuid primary key default gen_random_uuid(),
  return_id  uuid not null references returns(id) on delete cascade,
  type       text not null,
  message    text not null,
  metadata   jsonb not null default '{}'::jsonb,
  created_by uuid references profiles(id) on delete set null,
  created_at timestamptz not null default now()
);

create index if not exists idx_return_events_return on return_events(return_id, created_at desc);

-- ---------------------------------------------------------------------
-- Permission: returns.manage
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('returns.manage', 'Manage returns, RMA workflow, inspections and refunds.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'returns.manage'
where r.name in ('admin', 'manager', 'support')
on conflict do nothing;

-- RLS
do $$
begin
  execute 'drop policy if exists manager_all on public.returns';
  execute 'create policy manager_all on public.returns for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.return_items';
  execute 'create policy manager_all on public.return_items for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.return_events';
  execute 'create policy manager_all on public.return_events for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 016_coupons_promotions.sql
-- =====================================================================

-- =====================================================================
-- 016_coupons_promotions.sql
-- Phase 4.14 — Enterprise Coupons & Promotions
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- coupons — enterprise fields
-- ---------------------------------------------------------------------
alter table coupons
  add column if not exists name                 text,
  add column if not exists description          text,
  add column if not exists promo_type           text,
  add column if not exists timezone             text not null default 'Asia/Kolkata',
  add column if not exists max_discount         numeric(12,2) check (max_discount is null or max_discount >= 0),
  add column if not exists per_customer_limit   integer check (per_customer_limit is null or per_customer_limit >= 0),
  add column if not exists first_order_only     boolean not null default false,
  add column if not exists logged_in_only       boolean not null default false,
  add column if not exists eligibility          jsonb not null default '{}'::jsonb,
  add column if not exists allow_stack          boolean not null default false,
  add column if not exists priority             integer not null default 0,
  add column if not exists is_exclusive         boolean not null default false,
  add column if not exists auto_apply           boolean not null default false,
  add column if not exists auto_conditions      jsonb not null default '{}'::jsonb,
  add column if not exists buy_x_get_y          jsonb not null default '{}'::jsonb,
  add column if not exists free_shipping        jsonb not null default '{}'::jsonb,
  add column if not exists lifecycle_status     text not null default 'draft'
    check (lifecycle_status in ('draft','active','archived')),
  add column if not exists deleted_at           timestamptz,
  add column if not exists total_revenue        numeric(14,2) not null default 0 check (total_revenue >= 0);

update coupons set name = code where name is null;
update coupons set promo_type = case
  when type::text = 'percent' then 'percentage'
  when type::text = 'fixed' then 'fixed_amount'
  else 'percentage'
end where promo_type is null;

update coupons set lifecycle_status = case
  when is_active then 'active'
  else 'draft'
end where lifecycle_status = 'draft' and is_active = true;

create index if not exists idx_coupons_promo_type   on coupons(promo_type);
create index if not exists idx_coupons_lifecycle    on coupons(lifecycle_status);
create index if not exists idx_coupons_starts       on coupons(starts_at);
create index if not exists idx_coupons_expires      on coupons(expires_at);
create index if not exists idx_coupons_deleted      on coupons(deleted_at) where deleted_at is not null;

-- ---------------------------------------------------------------------
-- coupon_usage — discount tracking
-- ---------------------------------------------------------------------
alter table coupon_usage
  add column if not exists discount_amount numeric(14,2) not null default 0 check (discount_amount >= 0),
  add column if not exists order_subtotal  numeric(14,2);

create index if not exists idx_coupon_usage_customer on coupon_usage(customer_id);
create index if not exists idx_coupon_usage_order    on coupon_usage(order_id);

-- ---------------------------------------------------------------------
-- gift_cards — issuance fields
-- ---------------------------------------------------------------------
alter table gift_cards
  add column if not exists customer_id      uuid references customers(id) on delete set null,
  add column if not exists issued_to_email  text,
  add column if not exists issued_by        uuid references profiles(id) on delete set null,
  add column if not exists notes              text,
  add column if not exists name               text;

alter table gift_card_transactions
  add column if not exists notes       text,
  add column if not exists created_by    uuid references profiles(id) on delete set null;

create index if not exists idx_gift_cards_customer on gift_cards(customer_id);
create index if not exists idx_gift_cards_active   on gift_cards(is_active);

-- ---------------------------------------------------------------------
-- Permission already seeded: marketing.manage
-- ---------------------------------------------------------------------
do $$
begin
  execute 'drop policy if exists manager_all on public.coupons';
  execute 'create policy manager_all on public.coupons for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.coupon_usage';
  execute 'create policy manager_all on public.coupon_usage for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.gift_cards';
  execute 'create policy manager_all on public.gift_cards for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.gift_card_transactions';
  execute 'create policy manager_all on public.gift_card_transactions for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 017_shipping_logistics.sql
-- =====================================================================

-- =====================================================================
-- 017_shipping_logistics.sql
-- Phase 4.15 — Enterprise Shipping & Logistics
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- shipping_carriers
-- ---------------------------------------------------------------------
create table if not exists shipping_carriers (
  id                  uuid primary key default gen_random_uuid(),
  name                text not null,
  provider            text not null
                      check (provider in (
                        'delhivery','shiprocket','blue_dart','xpressbees',
                        'india_post','dtdc','ekart','amazon_shipping','custom'
                      )),
  api_key_encrypted   text,
  api_secret_encrypted text,
  sandbox             boolean not null default true,
  is_active           boolean not null default true,
  deleted_at          timestamptz,
  created_at          timestamptz not null default now(),
  updated_at          timestamptz not null default now()
);

create index if not exists idx_shipping_carriers_provider on shipping_carriers(provider);
create index if not exists idx_shipping_carriers_active   on shipping_carriers(is_active);

-- ---------------------------------------------------------------------
-- shipping_zones
-- ---------------------------------------------------------------------
create table if not exists shipping_zones (
  id           uuid primary key default gen_random_uuid(),
  name         text not null,
  country      text not null default 'India',
  state        text,
  city         text,
  postal_from  text,
  postal_to    text,
  priority     integer not null default 0,
  is_active    boolean not null default true,
  deleted_at   timestamptz,
  created_at   timestamptz not null default now(),
  updated_at   timestamptz not null default now()
);

create index if not exists idx_shipping_zones_priority on shipping_zones(priority desc);
create index if not exists idx_shipping_zones_country  on shipping_zones(country);

-- ---------------------------------------------------------------------
-- shipping_rates
-- ---------------------------------------------------------------------
create table if not exists shipping_rates (
  id                      uuid primary key default gen_random_uuid(),
  zone_id                 uuid not null references shipping_zones(id) on delete cascade,
  name                    text not null,
  weight_min_grams        integer not null default 0 check (weight_min_grams >= 0),
  weight_max_grams        integer check (weight_max_grams is null or weight_max_grams >= 0),
  price                   numeric(12,2) not null default 0 check (price >= 0),
  free_shipping_threshold numeric(12,2) check (free_shipping_threshold is null or free_shipping_threshold >= 0),
  cod_charge              numeric(12,2) not null default 0 check (cod_charge >= 0),
  is_active               boolean not null default true,
  deleted_at              timestamptz,
  created_at              timestamptz not null default now(),
  updated_at              timestamptz not null default now()
);

create index if not exists idx_shipping_rates_zone on shipping_rates(zone_id);

-- ---------------------------------------------------------------------
-- pickup_requests
-- ---------------------------------------------------------------------
create table if not exists pickup_requests (
  id           uuid primary key default gen_random_uuid(),
  carrier_id   uuid references shipping_carriers(id) on delete set null,
  warehouse_id uuid references warehouses(id) on delete set null,
  pickup_date  date not null,
  status       text not null default 'pending'
               check (status in ('pending','scheduled','picked_up','failed','cancelled')),
  reference    text,
  notes        text,
  created_at   timestamptz not null default now(),
  updated_at   timestamptz not null default now()
);

create index if not exists idx_pickup_requests_date   on pickup_requests(pickup_date);
create index if not exists idx_pickup_requests_status on pickup_requests(status);

-- ---------------------------------------------------------------------
-- ndr_events — non-delivery reports
-- ---------------------------------------------------------------------
create table if not exists ndr_events (
  id           uuid primary key default gen_random_uuid(),
  shipment_id  uuid not null references shipments(id) on delete cascade,
  reason       text not null
               check (reason in (
                 'customer_unavailable','wrong_address','refused','reschedule','rto'
               )),
  status       text not null default 'open'
               check (status in ('open','resolved','rto')),
  notes        text,
  scheduled_at timestamptz,
  resolved_at  timestamptz,
  created_at   timestamptz not null default now(),
  updated_at   timestamptz not null default now()
);

create index if not exists idx_ndr_events_shipment on ndr_events(shipment_id);
create index if not exists idx_ndr_events_status   on ndr_events(status);

-- ---------------------------------------------------------------------
-- shipments — logistics extensions
-- ---------------------------------------------------------------------
alter table shipments
  add column if not exists carrier_id   uuid references shipping_carriers(id) on delete set null,
  add column if not exists label_url    text,
  add column if not exists awb_number   text,
  add column if not exists cancelled_at timestamptz;

-- ---------------------------------------------------------------------
-- tracking_events — webhook-ready
-- ---------------------------------------------------------------------
alter table tracking_events
  add column if not exists event_type text not null default 'status'
    check (event_type in ('status','delivered','failed','returned','ndr','webhook')),
  add column if not exists raw        jsonb not null default '{}'::jsonb;

-- ---------------------------------------------------------------------
-- Permission: shipping.manage
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('shipping.manage', 'Manage carriers, zones, rates, shipments, pickups and NDR.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'shipping.manage'
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS
do $$
begin
  execute 'drop policy if exists manager_all on public.shipping_carriers';
  execute 'create policy manager_all on public.shipping_carriers for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.shipping_zones';
  execute 'create policy manager_all on public.shipping_zones for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.shipping_rates';
  execute 'create policy manager_all on public.shipping_rates for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.pickup_requests';
  execute 'create policy manager_all on public.pickup_requests for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.ndr_events';
  execute 'create policy manager_all on public.ndr_events for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 018_payments_gateway.sql
-- =====================================================================

-- =====================================================================
-- 018_payments_gateway.sql
-- Phase 4.16 — Enterprise Payment Gateway Architecture
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- payment_status — extended lifecycle
-- ---------------------------------------------------------------------
alter type payment_status add value if not exists 'captured';
alter type payment_status add value if not exists 'cancelled';
alter type payment_status add value if not exists 'voided';

-- ---------------------------------------------------------------------
-- payment_gateways
-- ---------------------------------------------------------------------
create table if not exists payment_gateways (
  id                      uuid primary key default gen_random_uuid(),
  display_name            text not null,
  provider                text not null
                          check (provider in (
                            'razorpay','cashfree','phonepe','payu','stripe','paypal','custom'
                          )),
  sandbox                 boolean not null default true,
  api_key_encrypted       text,
  api_secret_encrypted    text,
  webhook_secret_encrypted text,
  webhook_url             text,
  currency                char(3) not null default 'INR',
  is_enabled              boolean not null default false,
  priority                integer not null default 0,
  lifecycle_status        text not null default 'active'
                          check (lifecycle_status in ('active','archived')),
  deleted_at              timestamptz,
  created_at              timestamptz not null default now(),
  updated_at              timestamptz not null default now()
);

create index if not exists idx_payment_gateways_provider on payment_gateways(provider);
create index if not exists idx_payment_gateways_enabled  on payment_gateways(is_enabled);

-- ---------------------------------------------------------------------
-- payments — gateway extensions
-- ---------------------------------------------------------------------
alter table payments
  add column if not exists gateway_id       uuid references payment_gateways(id) on delete set null,
  add column if not exists customer_id      uuid references customers(id) on delete set null,
  add column if not exists payment_ref      text,
  add column if not exists gateway_txn_id   text,
  add column if not exists fees             numeric(14,2) not null default 0 check (fees >= 0),
  add column if not exists tax              numeric(14,2) not null default 0 check (tax >= 0),
  add column if not exists captured_at      timestamptz,
  add column if not exists failed_reason    text;

create index if not exists idx_payments_gateway   on payments(gateway_id);
create index if not exists idx_payments_customer  on payments(customer_id);
create index if not exists idx_payments_status      on payments(status);
create index if not exists idx_payments_gateway_txn on payments(gateway_txn_id);

-- ---------------------------------------------------------------------
-- payment_transactions — extended fields
-- ---------------------------------------------------------------------
alter table payment_transactions
  add column if not exists reference        text,
  add column if not exists gateway_txn_id   text,
  add column if not exists fees             numeric(14,2) not null default 0 check (fees >= 0),
  add column if not exists tax              numeric(14,2) not null default 0 check (tax >= 0);

-- ---------------------------------------------------------------------
-- payment_webhooks
-- ---------------------------------------------------------------------
create table if not exists payment_webhooks (
  id           uuid primary key default gen_random_uuid(),
  gateway_id   uuid references payment_gateways(id) on delete set null,
  payment_id   uuid references payments(id) on delete set null,
  event_type   text not null,
  payload      jsonb not null default '{}'::jsonb,
  signature    text,
  processed    boolean not null default false,
  processed_at timestamptz,
  error        text,
  created_at   timestamptz not null default now()
);

create index if not exists idx_payment_webhooks_gateway on payment_webhooks(gateway_id, created_at desc);
create index if not exists idx_payment_webhooks_processed on payment_webhooks(processed) where processed = false;

-- ---------------------------------------------------------------------
-- settlements
-- ---------------------------------------------------------------------
create table if not exists settlements (
  id               uuid primary key default gen_random_uuid(),
  gateway_id       uuid references payment_gateways(id) on delete set null,
  settlement_date  date not null,
  expected_amount  numeric(14,2) not null default 0 check (expected_amount >= 0),
  received_amount  numeric(14,2) not null default 0 check (received_amount >= 0),
  difference       numeric(14,2) not null default 0,
  status           text not null default 'pending'
                   check (status in ('pending','matched','mismatch','synced')),
  bank_reference   text,
  synced_at        timestamptz,
  created_at       timestamptz not null default now(),
  updated_at       timestamptz not null default now()
);

create index if not exists idx_settlements_date on settlements(settlement_date desc);

-- ---------------------------------------------------------------------
-- payment_reconciliation
-- ---------------------------------------------------------------------
create table if not exists payment_reconciliation (
  id                uuid primary key default gen_random_uuid(),
  reconciliation_date date not null default current_date,
  payment_id        uuid references payments(id) on delete set null,
  order_id          uuid references orders(id) on delete set null,
  settlement_id     uuid references settlements(id) on delete set null,
  expected_amount   numeric(14,2) not null default 0,
  actual_amount     numeric(14,2) not null default 0,
  status            text not null default 'pending'
                    check (status in ('pending','matched','mismatch')),
  notes             text,
  created_at        timestamptz not null default now()
);

create index if not exists idx_payment_reconciliation_status on payment_reconciliation(status);

-- ---------------------------------------------------------------------
-- payment_logs
-- ---------------------------------------------------------------------
create table if not exists payment_logs (
  id         uuid primary key default gen_random_uuid(),
  payment_id uuid references payments(id) on delete cascade,
  gateway_id uuid references payment_gateways(id) on delete set null,
  level      text not null default 'info'
             check (level in ('debug','info','warn','error')),
  message    text not null,
  metadata   jsonb not null default '{}'::jsonb,
  created_at timestamptz not null default now()
);

create index if not exists idx_payment_logs_payment on payment_logs(payment_id, created_at desc);

-- ---------------------------------------------------------------------
-- Permission: payments.manage
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('payments.manage', 'Manage payment gateways, transactions, settlements and reconciliation.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code = 'payments.manage'
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS
do $$
begin
  execute 'drop policy if exists manager_all on public.payment_gateways';
  execute 'create policy manager_all on public.payment_gateways for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.payment_webhooks';
  execute 'create policy manager_all on public.payment_webhooks for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.settlements';
  execute 'create policy manager_all on public.settlements for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.payment_reconciliation';
  execute 'create policy manager_all on public.payment_reconciliation for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.payment_logs';
  execute 'create policy manager_all on public.payment_logs for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 019_reports_analytics.sql
-- =====================================================================

-- =====================================================================
-- 019_reports_analytics.sql
-- Phase 4.17 — Enterprise Reports & Analytics
-- Additive + idempotent. Uses existing operational tables for data.
-- =====================================================================

-- ---------------------------------------------------------------------
-- saved_reports — user-saved filter/widget/layout presets
-- ---------------------------------------------------------------------
create table if not exists saved_reports (
  id            uuid primary key default gen_random_uuid(),
  name          text not null,
  report_type   text not null,
  filters       jsonb not null default '{}'::jsonb,
  widget_config jsonb not null default '{}'::jsonb,
  layout        jsonb not null default '[]'::jsonb,
  created_by    uuid references auth.users(id) on delete set null,
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now()
);

create index if not exists idx_saved_reports_user on saved_reports(created_by, updated_at desc);

-- ---------------------------------------------------------------------
-- scheduled_reports — automated report delivery
-- ---------------------------------------------------------------------
create table if not exists scheduled_reports (
  id            uuid primary key default gen_random_uuid(),
  name          text not null,
  report_type   text not null,
  frequency     text not null
                check (frequency in ('daily','weekly','monthly','quarterly','yearly')),
  email         text not null,
  filters       jsonb not null default '{}'::jsonb,
  format        text not null default 'csv'
                check (format in ('csv','excel','pdf')),
  is_enabled    boolean not null default true,
  last_run_at   timestamptz,
  next_run_at   timestamptz,
  created_by    uuid references auth.users(id) on delete set null,
  created_at    timestamptz not null default now(),
  updated_at    timestamptz not null default now()
);

create index if not exists idx_scheduled_reports_enabled on scheduled_reports(is_enabled) where is_enabled = true;

-- ---------------------------------------------------------------------
-- report_exports — export job history
-- ---------------------------------------------------------------------
create table if not exists report_exports (
  id            uuid primary key default gen_random_uuid(),
  report_type   text not null,
  format        text not null check (format in ('csv','excel','pdf','print')),
  status        text not null default 'completed'
                check (status in ('pending','completed','failed')),
  row_count     integer not null default 0,
  file_name     text,
  filters       jsonb not null default '{}'::jsonb,
  created_by    uuid references auth.users(id) on delete set null,
  created_at    timestamptz not null default now()
);

create index if not exists idx_report_exports_user on report_exports(created_by, created_at desc);

-- ---------------------------------------------------------------------
-- analytics_snapshots — pre-aggregated metric cache
-- ---------------------------------------------------------------------
create table if not exists analytics_snapshots (
  id             uuid primary key default gen_random_uuid(),
  snapshot_date  date not null default current_date,
  metric_key     text not null,
  metric_value   numeric(18,4) not null default 0,
  dimensions     jsonb not null default '{}'::jsonb,
  created_at     timestamptz not null default now(),
  unique (snapshot_date, metric_key, dimensions)
);

create index if not exists idx_analytics_snapshots_key on analytics_snapshots(metric_key, snapshot_date desc);

-- ---------------------------------------------------------------------
-- dashboard_widgets — per-user widget visibility & order
-- ---------------------------------------------------------------------
create table if not exists dashboard_widgets (
  id          uuid primary key default gen_random_uuid(),
  user_id     uuid not null references auth.users(id) on delete cascade,
  widget_key  text not null,
  visible     boolean not null default true,
  sort_order  integer not null default 0,
  config      jsonb not null default '{}'::jsonb,
  updated_at  timestamptz not null default now(),
  unique (user_id, widget_key)
);

create index if not exists idx_dashboard_widgets_user on dashboard_widgets(user_id, sort_order);

-- ---------------------------------------------------------------------
-- Permissions
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('reports.view', 'View reports and analytics dashboards.'),
  ('reports.export', 'Export reports to CSV, Excel and PDF.'),
  ('analytics.manage', 'Manage saved dashboards, scheduled reports and widget layouts.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code in ('reports.view', 'reports.export', 'analytics.manage')
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS
do $$
begin
  execute 'drop policy if exists manager_all on public.saved_reports';
  execute 'create policy manager_all on public.saved_reports for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.scheduled_reports';
  execute 'create policy manager_all on public.scheduled_reports for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.report_exports';
  execute 'create policy manager_all on public.report_exports for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.analytics_snapshots';
  execute 'create policy manager_all on public.analytics_snapshots for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.dashboard_widgets';
  execute 'create policy manager_all on public.dashboard_widgets for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 020_accounting_finance.sql
-- =====================================================================

-- =====================================================================
-- 020_accounting_finance.sql
-- Phase 4.18 — Enterprise Accounting & Finance
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- finance_vendors
-- ---------------------------------------------------------------------
create table if not exists finance_vendors (
  id                  uuid primary key default gen_random_uuid(),
  name                text not null,
  gst_number          text,
  pan                 text,
  bank_details        jsonb not null default '{}'::jsonb,
  contact_person      text,
  email               text,
  phone               text,
  payment_terms       text,
  outstanding_balance numeric(14,2) not null default 0,
  is_active           boolean not null default true,
  deleted_at          timestamptz,
  created_at          timestamptz not null default now(),
  updated_at          timestamptz not null default now()
);

create index if not exists idx_finance_vendors_name on finance_vendors(name);

-- ---------------------------------------------------------------------
-- expenses — extended fields
-- ---------------------------------------------------------------------
alter table expenses
  add column if not exists vendor_id       uuid references finance_vendors(id) on delete set null,
  add column if not exists gst_amount      numeric(14,2) not null default 0 check (gst_amount >= 0),
  add column if not exists invoice_number  text,
  add column if not exists invoice_date    date,
  add column if not exists payment_status  text not null default 'unpaid'
                                         check (payment_status in ('unpaid','partial','paid','scheduled')),
  add column if not exists attachments     jsonb not null default '[]'::jsonb,
  add column if not exists notes           text,
  add column if not exists deleted_at      timestamptz;

create index if not exists idx_expenses_vendor on expenses(vendor_id);
create index if not exists idx_expenses_payment_status on expenses(payment_status);
create index if not exists idx_expenses_spent_at on expenses(spent_at desc);

-- ---------------------------------------------------------------------
-- journal_entries
-- ---------------------------------------------------------------------
create table if not exists journal_entries (
  id                    uuid primary key default gen_random_uuid(),
  reference             text not null,
  narration             text,
  status                text not null default 'draft'
                        check (status in ('draft','pending','approved','reversed')),
  entry_date            date not null default current_date,
  total_debit           numeric(14,2) not null default 0 check (total_debit >= 0),
  total_credit          numeric(14,2) not null default 0 check (total_credit >= 0),
  reversed_by_entry_id  uuid references journal_entries(id) on delete set null,
  approved_by           uuid references auth.users(id) on delete set null,
  approved_at           timestamptz,
  created_by            uuid references auth.users(id) on delete set null,
  created_at            timestamptz not null default now(),
  updated_at            timestamptz not null default now()
);

create index if not exists idx_journal_entries_date on journal_entries(entry_date desc);
create index if not exists idx_journal_entries_status on journal_entries(status);

-- ---------------------------------------------------------------------
-- ledger_entries
-- ---------------------------------------------------------------------
create table if not exists ledger_entries (
  id                uuid primary key default gen_random_uuid(),
  ledger_type       text not null
                    check (ledger_type in ('general','sales','purchase','gst','customer','vendor')),
  account_code      text,
  reference         text,
  narration         text,
  debit             numeric(14,2) not null default 0 check (debit >= 0),
  credit            numeric(14,2) not null default 0 check (credit >= 0),
  currency          char(3) not null default 'INR',
  entry_date        date not null default current_date,
  journal_entry_id  uuid references journal_entries(id) on delete set null,
  vendor_id         uuid references finance_vendors(id) on delete set null,
  customer_id       uuid references customers(id) on delete set null,
  order_id          uuid references orders(id) on delete set null,
  expense_id        uuid references expenses(id) on delete set null,
  created_by        uuid references auth.users(id) on delete set null,
  created_at        timestamptz not null default now()
);

create index if not exists idx_ledger_entries_type on ledger_entries(ledger_type, entry_date desc);
create index if not exists idx_ledger_entries_journal on ledger_entries(journal_entry_id);

-- ---------------------------------------------------------------------
-- bank_accounts
-- ---------------------------------------------------------------------
create table if not exists bank_accounts (
  id             uuid primary key default gen_random_uuid(),
  name           text not null,
  bank_name      text not null,
  account_number text not null,
  ifsc           text,
  balance        numeric(14,2) not null default 0,
  currency       char(3) not null default 'INR',
  is_active      boolean not null default true,
  created_at     timestamptz not null default now(),
  updated_at     timestamptz not null default now()
);

-- ---------------------------------------------------------------------
-- bank_transactions
-- ---------------------------------------------------------------------
create table if not exists bank_transactions (
  id                 uuid primary key default gen_random_uuid(),
  bank_account_id    uuid not null references bank_accounts(id) on delete cascade,
  type               text not null check (type in ('credit','debit')),
  amount             numeric(14,2) not null check (amount >= 0),
  reference          text,
  description        text,
  transaction_date   date not null default current_date,
  matched            boolean not null default false,
  reconciliation_id  uuid,
  payment_id         uuid references payments(id) on delete set null,
  settlement_id      uuid references settlements(id) on delete set null,
  created_at         timestamptz not null default now()
);

create index if not exists idx_bank_transactions_account on bank_transactions(bank_account_id, transaction_date desc);

-- ---------------------------------------------------------------------
-- bank_reconciliation
-- ---------------------------------------------------------------------
create table if not exists bank_reconciliation (
  id               uuid primary key default gen_random_uuid(),
  bank_account_id  uuid not null references bank_accounts(id) on delete cascade,
  statement_date   date not null,
  opening_balance  numeric(14,2) not null default 0,
  closing_balance  numeric(14,2) not null default 0,
  matched_count    integer not null default 0,
  unmatched_count  integer not null default 0,
  status           text not null default 'pending'
                   check (status in ('pending','partial','reconciled')),
  notes            text,
  reconciled_at    timestamptz,
  created_by       uuid references auth.users(id) on delete set null,
  created_at       timestamptz not null default now(),
  updated_at       timestamptz not null default now()
);

-- link bank_transactions.reconciliation_id
do $$
begin
  if not exists (
    select 1 from pg_constraint where conname = 'bank_transactions_reconciliation_id_fkey'
  ) then
    alter table bank_transactions
      add constraint bank_transactions_reconciliation_id_fkey
      foreign key (reconciliation_id) references bank_reconciliation(id) on delete set null;
  end if;
exception when others then null;
end $$;

-- ---------------------------------------------------------------------
-- vendor_payments
-- ---------------------------------------------------------------------
create table if not exists vendor_payments (
  id              uuid primary key default gen_random_uuid(),
  vendor_id       uuid not null references finance_vendors(id) on delete restrict,
  expense_id      uuid references expenses(id) on delete set null,
  amount          numeric(14,2) not null check (amount > 0),
  payment_status  text not null default 'scheduled'
                  check (payment_status in ('scheduled','paid','partial','cancelled')),
  scheduled_date  date,
  paid_at         timestamptz,
  reference       text,
  notes           text,
  created_by      uuid references auth.users(id) on delete set null,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists idx_vendor_payments_vendor on vendor_payments(vendor_id, created_at desc);

-- ---------------------------------------------------------------------
-- gst_reports — extended metadata
-- ---------------------------------------------------------------------
alter table gst_reports
  add column if not exists report_type   text not null default 'monthly'
                                         check (report_type in ('monthly','quarterly','yearly','summary')),
  add column if not exists input_credit  numeric(14,2) not null default 0,
  add column if not exists output_tax    numeric(14,2) not null default 0,
  add column if not exists gst_payable   numeric(14,2) not null default 0,
  add column if not exists exported_at   timestamptz;

-- ---------------------------------------------------------------------
-- Permissions
-- ---------------------------------------------------------------------
insert into permissions (code, description) values
  ('finance.view', 'View accounting dashboard, ledger and GST reports.'),
  ('finance.manage', 'Manage expenses, vendors, journal entries and reconciliation.'),
  ('finance.export', 'Export financial reports and GST data.')
on conflict (code) do nothing;

insert into role_permissions (role_id, permission_id)
select r.id, p.id
from roles r
join permissions p on p.code in ('finance.view', 'finance.manage', 'finance.export')
where r.name in ('admin', 'manager')
on conflict do nothing;

-- RLS
do $$
begin
  execute 'drop policy if exists manager_all on public.finance_vendors';
  execute 'create policy manager_all on public.finance_vendors for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.journal_entries';
  execute 'create policy manager_all on public.journal_entries for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.ledger_entries';
  execute 'create policy manager_all on public.ledger_entries for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.bank_accounts';
  execute 'create policy manager_all on public.bank_accounts for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.bank_transactions';
  execute 'create policy manager_all on public.bank_transactions for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.bank_reconciliation';
  execute 'create policy manager_all on public.bank_reconciliation for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
  execute 'drop policy if exists manager_all on public.vendor_payments';
  execute 'create policy manager_all on public.vendor_payments for all to authenticated using (public.is_manager() or public.is_staff()) with check (public.is_manager() or public.is_staff())';
exception when others then null;
end $$;

-- =====================================================================
-- FILE: 021_marketing_automation.sql
-- =====================================================================

-- =====================================================================
-- 021_marketing_automation.sql
-- Phase 4.19 — Enterprise Marketing Automation
-- Additive + idempotent.
-- =====================================================================

-- ---------------------------------------------------------------------
-- marketing_templates
-- ---------------------------------------------------------------------
create table if not exists marketing_templates (
  id              uuid primary key default gen_random_uuid(),
  name            text not null,
  channel         text not null check (channel in ('email','whatsapp','push')),
  subject         text,
  preview_text    text,
  body_html       text,
  body_text       text,
  title           text,
  message         text,
  image_url       text,
  deep_link       text,
  media_url       text,
  buttons         jsonb not null default '[]'::jsonb,
  variables       jsonb not null default '[]'::jsonb,
  status          text not null default 'active' check (status in ('active','archived')),
  deleted_at      timestamptz,
  created_by      uuid references auth.users(id) on delete set null,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists idx_marketing_templates_channel on marketing_templates(channel, status);

-- ---------------------------------------------------------------------
-- marketing_segments
-- ---------------------------------------------------------------------
create table if not exists marketing_segments (
  id              uuid primary key default gen_random_uuid(),
  name            text not null,
  slug            text not null unique,
  description     text,
  segment_type    text not null default 'custom'
                  check (segment_type in ('preset','custom')),
  criteria        jsonb not null default '{}'::jsonb,
  customer_count  integer not null default 0,
  is_active       boolean not null default true,
  deleted_at      timestamptz,
  created_by      uuid references auth.users(id) on delete set null,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists idx_marketing_segments_slug on marketing_segments(slug);

-- ---------------------------------------------------------------------
-- marketing_campaigns
-- ---------------------------------------------------------------------
create table if not exists marketing_campaigns (
  id                uuid primary key default gen_random_uuid(),
  name              text not null,
  campaign_type     text not null check (campaign_type in ('email','whatsapp','push','sms')),
  status            text not null default 'draft'
                    check (status in ('draft','scheduled','running','paused','completed','cancelled')),
  template_id       uuid references marketing_templates(id) on delete set null,
  segment_id        uuid references marketing_segments(id) on delete set null,
  subject           text,
  preview_text      text,
  sender_name       text,
  reply_to          text,
  title             text,
  message           text,
  image_url         text,
  deep_link         text,
  media_url         text,
  buttons           jsonb not null default '[]'::jsonb,
  scheduled_at      timestamptz,
  started_at        timestamptz,
  completed_at      timestamptz,
  sent_count        integer not null default 0,
  delivered_count   integer not null default 0,
  opened_count      integer not null default 0,
  clicked_count     integer not null default 0,
  bounced_count     integer not null default 0,
  conversion_count  integer not null default 0,
  revenue           numeric(14,2) not null default 0,
  deleted_at        timestamptz,
  created_by        uuid references auth.users(id) on delete set null,
  created_at        timestamptz not null default now(),
  updated_at        timestamptz not null default now()
);

create index if not exists idx_marketing_campaigns_type on marketing_campaigns(campaign_type, status);
create index if not exists idx_marketing_campaigns_scheduled on marketing_campaigns(scheduled_at) where status = 'scheduled';

-- ---------------------------------------------------------------------
-- marketing_automation
-- ---------------------------------------------------------------------
create table if not exists marketing_automation (
  id              uuid primary key default gen_random_uuid(),
  name            text not null,
  slug            text not null unique,
  description     text,
  workflow_type   text not null,
  trigger_event   text not null,
  delay_minutes   integer not null default 0 check (delay_minutes >= 0),
  segment_id      uuid references marketing_segments(id) on delete set null,
  action_type     text not null check (action_type in ('email','whatsapp','push','sms')),
  template_id     uuid references marketing_templates(id) on delete set null,
  is_enabled      boolean not null default false,
  last_run_at     timestamptz,
  run_count       integer not null default 0,
  created_by      uuid references auth.users(id) on delete set null,
  created_at      timestamptz not null default now(),
  updated_at      timestamptz not null default now()
);

create index if not exists idx_marketing_automation_enabled on marketing_automation(is_enabled) where is_enabled = true;

-- ---------------------------------------------------------------------
-- campaign_recipients
-- ---------------------------------------------------------------------
create table if not exists campaign_recipients (
  id              uuid primary key default gen_random_uuid(),
  campaign_id     uuid not null references marketing_campaigns(id) on delete cascade,
  customer_id     uuid references customers(id) on delete set null,
  email           text,
  phone           text,
  status          text not null default 'pending'
                  check (status in ('pending','queued','sent','delivered','opened','clicked','bounced','failed')),
  sent_at         timestamptz,
  opened_at       timestamptz,
  clicked_at      timestamptz,
  metadata        jsonb not null default '{}'::jsonb,
  created_at      timestamptz not null default now()
);

create index if not exists idx_campaign_recipients_campaign on campaign_recipients(campaign_id, status);

-- ---------------------------------------------------------------------
-- campaign_events
-- ---------------------------------------------------------------------
create table if not exists campaign_events (
  id              uuid primary key default gen_random_uuid(),
  campaign_id     uuid not null references marketing_campaigns(id) on delete cascade,
  recipient_id    uuid references campaign_recipients(id) on delete set null,
  event_type      text not null check (event_type in ('send','deliver','open','click','bounce','conversion')),
  metadata        jsonb not null default '{}'::jsonb,
  created_at      timestamptz not null default now()
);

create index if not exists idx_campaign_events_campaign on campaign_events(campaign_id, created_at desc);

-- ---------------------------------------------------------------------
-- email_queue
-- ---------------------------------------------------------------------
create table if not exists email_queue (
  id              uuid primary key default gen_random_uuid(),
  campaign_id     uuid references marketing_campaigns(id) on delete cascade,
  recipient_id    uuid references campaign_recipients(id) on delete cascade,
  to_email        text not null,
  subject         text not null,
  body_html       text,
  body_text       text,
  status          text not null default 'queued'
                  check (status in ('queued','processing','sent','failed')),
  scheduled_at    timestamptz,
  sent_at         timestamptz,
  error           text,
  created_at      timestamptz not null default now()
);

create index if not exists idx_email_queue_status on email_queue(status, scheduled_at);

-- ---------------------------------------------------------------------
-- whatsapp_queue
-- ---------------------------------------------------------------------
create table if not exists whatsapp_queue (
  id              uuid primary key default gen_random_uuid(),
  campaign_id     uuid references marketing_campaigns(id) on delete cascade,
  recipient_id    uuid references campaign_recipients(id) on delete cascade,
  to_phone        text not null,
  template_name   text,
  body            text,
  media_url       text,
  buttons         jsonb not null default '[]'::jsonb,
  status          text not null default 'queued'
                  check (status in ('queued','processing','sent','failed')),
  scheduled_at    timestamptz,
  sent_at         timestamptz,
  error           text,
  created_at      timestamptz not null default now()
);

create index if not exists idx_whatsapp_queue_status on whatsapp_queue(status, scheduled_at);

-- ---------------------------------------------------------------------
-- push_queue
-- ---------------------------------------------------------------------
create table if not exists push_queue (
  id              uuid primary key default gen_random_uuid(),
  campaign_id     uuid references marketing_campaigns(id) on delete cascade,
  recipient_id    uuid references campaign_recipients(id) on delete cascade,
  user_id         uuid references auth.users(id) on delete set null,
  title           text not null,
  message         text not null,
  image_url       text,
  deep_link       text,
  status          text not null default 'queued'
                  check (status in ('queued','processing','sent','failed')),
  scheduled_at    timestamptz,
  sent_at         timestamptz,
  error           text,
  created_at      timestamptz not null default now()
);

create index if not exists idx_push_queue_status on push_queue(status, scheduled_at);

