  ('reports.view',      'View reports and analytics dashboards.'),
  ('reports.export',    'Export reports to CSV, Excel and PDF.'),
  ('analytics.manage',  'Manage saved dashboards, scheduled reports and widget layouts.'),
  ('finance.view',      'View accounting dashboard, ledger and GST reports.'),
  ('finance.manage',    'Manage expenses, vendors, journal entries and reconciliation.'),
  ('finance.export',    'Export financial reports and GST data.'),
  ('accounting.manage', 'Manage expenses, transactions and GST reports.'),
  ('settings.manage',   'Manage global system settings.')
on conflict (code) do nothing;

-- ---------------------------------------------------------------------
-- 3. Admin role receives every permission
-- ---------------------------------------------------------------------
insert into public.role_permissions (role_id, permission_id)
select r.id, p.id
from public.roles r
cross join public.permissions p
where r.name = 'admin'
on conflict do nothing;

-- ---------------------------------------------------------------------
-- 4. Auth RPCs used by the admin app (repair if 006 was skipped)
-- ---------------------------------------------------------------------
create or replace function public.current_user_role()
returns text
language sql
stable
security definer
set search_path = public
as $$
  select r.name
  from profiles p
  join roles r on r.id = p.role_id
  where p.id = auth.uid()
    and p.is_active
  limit 1;
$$;

create or replace function public.current_user_permissions()
returns setof text
language sql
stable
security definer
set search_path = public
as $$
  select distinct perm.code
  from profiles p
  join role_permissions rp on rp.role_id = p.role_id
  join permissions perm on perm.id = rp.permission_id
  where p.id = auth.uid()
    and p.is_active;
$$;

grant execute on function public.current_user_role()        to authenticated;
grant execute on function public.current_user_permissions() to authenticated;

-- =====================================================================
-- FILE: 023_delhivery_integration.sql
-- =====================================================================

-- =====================================================================
-- BeyondBabyCo — 023_delhivery_integration.sql
-- Delhivery courier integration: tracking history, API logs, shipment fields.
-- Compatible with existing shipments schema (tracking_number, carrier).
-- Idempotent — safe to re-run.
-- =====================================================================

-- Only add columns that do not exist on the current shipments table.
alter table public.shipments
  add column if not exists pickup_status text,
  add column if not exists manifest_url  text,
  add column if not exists label_url     text;

create index if not exists idx_shipments_tracking on public.shipments(tracking_number);
create index if not exists idx_shipments_carrier  on public.shipments(carrier);

-- Detailed courier scan timeline (complements tracking_events)
create table if not exists public.shipment_tracking (
  id              uuid primary key default gen_random_uuid(),
  shipment_id     uuid not null references public.shipments(id) on delete cascade,
  order_id        uuid not null references public.orders(id) on delete cascade,
  tracking_number text,
  status          text not null,
  status_code     text,
  message         text,
  location        text,
  event_time      timestamptz not null default now(),
  raw             jsonb not null default '{}'::jsonb,
  created_at      timestamptz not null default now()
);

create index if not exists idx_shipment_tracking_shipment  on public.shipment_tracking(shipment_id);
create index if not exists idx_shipment_tracking_order     on public.shipment_tracking(order_id);
create index if not exists idx_shipment_tracking_tracking  on public.shipment_tracking(tracking_number);

-- Delhivery / courier API request logs
create table if not exists public.courier_logs (
  id            uuid primary key default gen_random_uuid(),
  shipment_id   uuid references public.shipments(id) on delete set null,
  order_id      uuid references public.orders(id) on delete set null,
  courier_name  text not null default 'delhivery',
  action        text not null,
  request_url   text,
  request_body  jsonb,
  response_body jsonb,
  status_code   integer,
  success       boolean not null default false,
  error_message text,
  created_at    timestamptz not null default now()
);

create index if not exists idx_courier_logs_shipment on public.courier_logs(shipment_id);
create index if not exists idx_courier_logs_order    on public.courier_logs(order_id);
create index if not exists idx_courier_logs_action   on public.courier_logs(action);

alter table public.shipment_tracking enable row level security;
alter table public.courier_logs enable row level security;

-- ---------------------------------------------------------------------
-- RLS — uses current_user_role() / current_user_permissions() from
-- 006_auth_functions.sql (same approach as the Next.js app guards).
-- Does NOT depend on is_staff() / is_manager() from 003_rls.sql.
-- ---------------------------------------------------------------------

-- Staff with shipping.manage or orders.manage: full access to tracking rows
drop policy if exists staff_all_shipment_tracking on public.shipment_tracking;
drop policy if exists shipping_manage_all on public.shipment_tracking;
create policy shipping_manage_all on public.shipment_tracking
  for all to authenticated
  using (
    public.current_user_role() = 'admin'
    or exists (
      select 1 from public.current_user_permissions() as perm
      where perm in ('shipping.manage', 'orders.manage')
    )
  )
  with check (
    public.current_user_role() = 'admin'
    or exists (
      select 1 from public.current_user_permissions() as perm
      where perm in ('shipping.manage', 'orders.manage')
    )
  );

-- Support staff with orders.view: read-only tracking timeline
drop policy if exists orders_view_read on public.shipment_tracking;
create policy orders_view_read on public.shipment_tracking
  for select to authenticated
  using (
    exists (
      select 1 from public.current_user_permissions() as perm
      where perm = 'orders.view'
    )
  );

-- Customers: read tracking for their own orders
drop policy if exists customer_read_shipment_tracking on public.shipment_tracking;
create policy customer_read_shipment_tracking on public.shipment_tracking
  for select to authenticated
  using (
    exists (
      select 1 from public.orders o
      join public.customers c on c.id = o.customer_id
      where o.id = shipment_tracking.order_id
        and c.profile_id = auth.uid()
    )
  );

-- Courier API logs: staff with shipping/orders manage permissions only
drop policy if exists staff_all_courier_logs on public.courier_logs;
drop policy if exists shipping_manage_all on public.courier_logs;
create policy shipping_manage_all on public.courier_logs
  for all to authenticated
  using (
    public.current_user_role() = 'admin'
    or exists (
      select 1 from public.current_user_permissions() as perm
      where perm in ('shipping.manage', 'orders.manage')
    )
  )
  with check (
    public.current_user_role() = 'admin'
    or exists (
      select 1 from public.current_user_permissions() as perm
      where perm in ('shipping.manage', 'orders.manage')
    )
  );

-- =====================================================================
-- FILE: 024_storefront_coupons.sql
-- =====================================================================

-- =====================================================================
-- 024_storefront_coupons.sql
-- Storefront coupon seed + public read policy for cart validation API.
--
-- The coupons table is defined in 001_initial_schema.sql. Column mapping
-- for the storefront API:
--   discount_type  -> type          (enum: percent | fixed; "flat" = fixed)
--   discount_value -> value
--   min_order_value -> min_order
--   usage_limit    -> max_uses
--   valid_from     -> starts_at
--   valid_until    -> expires_at
--   max_discount   -> max_discount  (added in 016)
-- =====================================================================

-- Allow anonymous/authenticated clients to read active coupons for validation.
drop policy if exists storefront_read_active_coupons on public.coupons;
create policy storefront_read_active_coupons on public.coupons
  for select
  to anon, authenticated
  using (
    is_active = true
    and deleted_at is null
    and lifecycle_status = 'active'
  );

-- ---------------------------------------------------------------------
-- Seed storefront coupon codes (idempotent upsert)
-- ---------------------------------------------------------------------
insert into public.coupons (
  code,
  type,
  value,
  min_order,
  max_uses,
  used_count,
  is_active,
  lifecycle_status,
  promo_type,
  name,
  starts_at
)
values
  ('WELCOME10', 'percent', 10, 0, 100, 0, true, 'active', 'percentage', 'Welcome 10% Off', now()),
  ('BABY15', 'percent', 15, 499, 100, 0, true, 'active', 'percentage', 'Baby 15% Off', now()),
  ('FLAT100', 'fixed', 100, 599, 100, 0, true, 'active', 'fixed_amount', 'Flat ₹100 Off', now()),
  ('FIRSTORDER', 'percent', 20, 0, 100, 0, true, 'active', 'percentage', 'First Order 20% Off', now())
on conflict (code) do update set
  type = excluded.type,
  value = excluded.value,
  min_order = excluded.min_order,
  max_uses = excluded.max_uses,
  is_active = excluded.is_active,
  lifecycle_status = excluded.lifecycle_status,
  promo_type = excluded.promo_type,
  name = excluded.name,
  updated_at = now();

-- =====================================================================
-- FILE: 025_product_gst_rates.sql
-- =====================================================================

-- =====================================================================
-- 025_product_gst_rates.sql
-- Align product GST rates: 12% baby care, 18% hair/ayurvedic oils.
-- Idempotent — safe to re-run.
-- =====================================================================

update public.products p
set gst_rate = 18, updated_at = now()
from public.categories c
where p.category_id = c.id
  and c.slug in ('baby-oil', 'massage-oil');

update public.products p
set gst_rate = 12, updated_at = now()
from public.categories c
where p.category_id = c.id
  and c.slug in (
    'baby-wipes',
    'baby-wash',
    'baby-lotion',
    'baby-shampoo',
    'baby-cream',
    'baby-powder',
    'baby-soap',
    'diaper-rash-cream',
    'gift-sets',
    'travel-kits',
    'accessories',
    'mother-care'
  );

-- Default any remaining zero/null baby catalog products to 12%
update public.products
set gst_rate = 12, updated_at = now()
where (gst_rate is null or gst_rate = 0)
  and deleted_at is null;

-- =====================================================================
-- FILE: 026_product_availability_waitlist.sql
-- =====================================================================

-- =====================================================================
-- 026_product_availability_waitlist.sql
-- Launch product stock/status + waitlist_emails for Notify Me signups.
-- =====================================================================

create table if not exists public.waitlist_emails (
  id         uuid primary key default gen_random_uuid(),
  email      text not null,
  product_id uuid not null references public.products(id) on delete cascade,
  created_at timestamptz not null default now(),
  unique (email, product_id)
);

create index if not exists idx_waitlist_emails_product on public.waitlist_emails(product_id);
create index if not exists idx_waitlist_emails_created on public.waitlist_emails(created_at desc);

alter table public.waitlist_emails enable row level security;

drop policy if exists public_insert_waitlist_emails on public.waitlist_emails;
create policy public_insert_waitlist_emails on public.waitlist_emails
  for insert
  to anon, authenticated
  with check (true);

-- ---------------------------------------------------------------------
-- Launch products: active with stock
-- ---------------------------------------------------------------------
update public.products
set
  status = 'active',
  stock = 500,
  published_at = coalesce(published_at, now())
where slug = 'pure-gentle-water-baby-wipes'
  and deleted_at is null;

update public.products
set
  status = 'active',
  stock = 180,
  published_at = coalesce(published_at, now())
where slug = 'ayurvedic-massage-oil'
  and deleted_at is null;

-- Wipes: keep only 72-count and 144-count variants active
update public.product_variants pv
set name = '144 Wipes', sku = 'BBC-WIPES-PURE-144'
from public.products p
where pv.product_id = p.id
  and p.slug = 'pure-gentle-water-baby-wipes'
  and pv.sku = 'BBC-WIPES-PURE-120';

update public.product_variants pv
set is_active = false
from public.products p
where pv.product_id = p.id
  and p.slug = 'pure-gentle-water-baby-wipes'
  and pv.sku not in ('BBC-WIPES-PURE-72', 'BBC-WIPES-PURE-144');

update public.product_variants pv
set is_active = true
from public.products p
where pv.product_id = p.id
  and p.slug = 'pure-gentle-water-baby-wipes'
  and pv.sku in ('BBC-WIPES-PURE-72', 'BBC-WIPES-PURE-144');

-- ---------------------------------------------------------------------
-- All other storefront products: coming soon (no purchasable stock)
-- ---------------------------------------------------------------------
update public.products
set
  status = 'coming_soon',
  stock = 0,
  published_at = null
where slug not in ('pure-gentle-water-baby-wipes', 'ayurvedic-massage-oil')
  and deleted_at is null
  and status in ('active', 'coming_soon');

-- =====================================================================
-- FILE: 027_waitlist.sql
